// import { useState } from 'react';
import './App.css';


const App = () => {
  let i =0 ;
  return(
    <div className="App">
      <h1>
        <button onClick={()=> {++i}} >+</button><br></br>
        {i}      <br></br>
        <button onClick={()=> {--i}} >-</button><br></br>
      </h1>
    </div>
  )
}

export default App;
